mapper.select:
SELECT id, title, achievementType, dept_id AS deptId, is_classified AS isClassified, status, score, authors, publish_year AS publishYear, dept_name AS deptName FROM (
-- Paper branch SELECT p.id, p.title AS title, 'paper' AS achievementType, p.dept_id, p.is_classified, p.status, MATCH(p.title, p.authors, p.abstract_text) AGAINST (#{sanitizedKeyword} IN BOOLEAN MODE) AS score, p.authors, p.publish_year, d.dept_name FROM paper p LEFT JOIN sys_department d ON p.dept_id = d.id WHERE MATCH(p.title, p.authors, p.abstract_text) AGAINST (#{sanitizedKeyword} IN BOOLEAN MODE) AND p.status != 'DRAFT' AND p.status != 'INVALIDATED' AND p.dept_id = #{deptId}
UNION ALL
-- Patent branch SELECT pat.id, pat.patent_name AS title, 'patent' AS achievementType, pat.dept_id, pat.is_classified, pat.status, MATCH(pat.patent_name, pat.inventors) AGAINST (#{sanitizedKeyword} IN BOOLEAN MODE) AS score, pat.inventors AS authors, YEAR(pat.application_date) AS publish_year, d.dept_name FROM patent pat LEFT JOIN sys_department d ON pat.dept_id = d.id WHERE MATCH(pat.patent_name, pat.inventors) AGAINST (#{sanitizedKeyword} IN BOOLEAN MODE) AND pat.status != 'DRAFT' AND pat.status != 'INVALIDATED' AND pat.dept_id = #{deptId}
UNION ALL
-- Software Copyright branch SELECT sc.id, sc.name AS title, 'software' AS achievementType, sc.dept_id, sc.is_classified, sc.status, MATCH(sc.name, sc.copyright_holder) AGAINST (#{sanitizedKeyword} IN BOOLEAN MODE) AS score, sc.copyright_holder AS authors, YEAR(sc.registration_date) AS publish_year, d.dept_name FROM software_copyright sc LEFT JOIN sys_department d ON sc.dept_id = d.id WHERE MATCH(sc.name, sc.copyright_holder) AGAINST (#{sanitizedKeyword} IN BOOLEAN MODE) AND sc.status != 'DRAFT' AND sc.status != 'INVALIDATED' AND sc.dept_id = #{deptId}
) AS results
AND results.is_classified = 0
AND results.is_classified = 0 AND results.is_classified = 1
AND results.achievementType = #{type}
AND results.publish_year >= #{yearFrom}
AND results.publish_year <= #{yearTo}
ORDER BY score DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*) FROM (
-- Paper branch SELECT p.id, p.is_classified, 'paper' AS achievementType, p.publish_year FROM paper p WHERE MATCH(p.title, p.authors, p.abstract_text) AGAINST (#{sanitizedKeyword} IN BOOLEAN MODE) AND p.status != 'DRAFT' AND p.status != 'INVALIDATED' AND p.dept_id = #{deptId}
UNION ALL
-- Patent branch SELECT pat.id, pat.is_classified, 'patent' AS achievementType, YEAR(pat.application_date) AS publish_year FROM patent pat WHERE MATCH(pat.patent_name, pat.inventors) AGAINST (#{sanitizedKeyword} IN BOOLEAN MODE) AND pat.status != 'DRAFT' AND pat.status != 'INVALIDATED' AND pat.dept_id = #{deptId}
UNION ALL
-- Software Copyright branch SELECT sc.id, sc.is_classified, 'software' AS achievementType, YEAR(sc.registration_date) AS publish_year FROM software_copyright sc WHERE MATCH(sc.name, sc.copyright_holder) AGAINST (#{sanitizedKeyword} IN BOOLEAN MODE) AND sc.status != 'DRAFT' AND sc.status != 'INVALIDATED' AND sc.dept_id = #{deptId}
) AS count_results
AND count_results.is_classified = 0
AND count_results.is_classified = 0 AND count_results.is_classified = 1
AND count_results.achievementType = #{type}
AND count_results.publish_year >= #{yearFrom}
AND count_results.publish_year <= #{yearTo}
